const normalizeBarcode = (bc: string | null | undefined) => bc?.trim() || "";

const formatPrice = (price: number) => {
  return new Intl.NumberFormat("en-US").format(price) + " Ks";
};

// Helper function to validate and format image URLs
const getValidImageUrl = (url: string | null | undefined) => {
  if (!url) return null;
  
  // Return valid URLs, data URIs, and Supabase storage URLs as-is
  if (url.startsWith('data:') || url.startsWith('http') || url.startsWith('/') || 
      url.includes('supabase.co/storage')) {
    return url;
  }
  
  // Only treat as Base64 if it looks like valid Base64 and is reasonably long
  if (isValidBase64Image(url)) {
    return `data:image/jpeg;base64,${url}`;
  }
  
  // For other cases, assume it's invalid data and return null to trigger fallback
  return null;
};

// Helper function to validate Base64 strings
const isValidBase64Image = (str: string) => {
  // Base64 should be at least 100 characters and contain only valid characters
  if (str.length < 100 || str.includes(' ')) return false;
  
  // Check if string contains only valid Base64 characters
  const base64Regex = /^[A-Za-z0-9+/=]+$/;
  if (!base64Regex.test(str)) return false;
  
  // Additional check: proper length (multiple of 4 for padding)
  return str.length % 4 === 0;
};

