  onUpdatePrice,
  onRemoveItem,
  totalAmount,
  customerName,
  onCustomerNameChange,
  customerPhone,
  onCustomerPhoneChange,
  customerAddress,
  onCustomerAddressChange,
  saleType,
  onSaleTypeChange,
  paymentMethod,
  onPaymentMethodChange,
  courierName,
  onCourierNameChange,
